collapsible-controlled:
import * as React from "react"

import {
  Collapsible,
  CollapsiblePanel,
  CollapsibleTrigger,
} from "@/components/ui/collapsible"

import { ChevronDownIcon, Trash2Icon } from "lucide-react"

import { Button } from "@/components/ui/button"



function CollapsibleControlledPreview() {
  const [open, setOpen] = React.useState(false)

  return (
    <div className="flex w-full max-w-sm flex-col gap-3">
      <Collapsible
        className="rounded-lg border border-border"
        open={open}
        onOpenChange={setOpen}
      >
        <CollapsibleTrigger className="flex w-full items-center justify-between gap-3 px-4 py-3.5 text-left font-medium text-sm">
          {open ? "Hide" : "Show"} details
          <ChevronDownIcon className="size-4 shrink-0 text-muted-foreground transition-transform duration-200" />
        </CollapsibleTrigger>
        <CollapsiblePanel>
          <div className="px-4 pb-4 text-sm text-muted-foreground">
            This collapsible is controlled externally. Current state:{" "}
            <code className="rounded bg-muted px-1.5 py-0.5 font-mono text-xs text-foreground">
              {String(open)}
            </code>
          </div>
        </CollapsiblePanel>
      </Collapsible>
      <Button
        onClick={() => setOpen((value) => !value)}
        size="sm"
        variant="outline"
      >
        Toggle externally
      </Button>
    </div>
  )
}

