function validateEmail(value: unknown) {
  if (typeof value !== "string") {
    return "Email must be a string."
  }

  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value) ? null : "Enter a valid email address."
}

const roleOptions: Array<{ label: string; value: Role }> = [
  { label: "Product Designer", value: "Product Designer" },
  { label: "Frontend Engineer", value: "Frontend Engineer" },
  { label: "Engineering Manager", value: "Engineering Manager" },
]

const workModeOptions = [
  {
    label: "Onsite",
    value: "Onsite" as const,
    description: "Primarily office-based with in-person rituals.",
  },
  {
    label: "Hybrid",
    value: "Hybrid" as const,
    description: "Splits time between collaboration days and remote focus.",
  },
  {
    label: "Remote",
    value: "Remote" as const,
    description: "Works fully distributed across time zones.",
  },
]

function ActionsCell({ row, table }: { row: Row<TeamMember>; table: Table<TeamMember> }) {
  return (
    <DropdownMenu>
      <DropdownMenuTrigger
        render={
          <Button className="size-7" size="icon" variant="ghost">
            <MoreHorizontalIcon />
          </Button>
        }
      />
      <DropdownMenuContent side="bottom" align="start">
        <DropdownMenuItem onClick={() => table.options.meta?.editing?.openDialog(row.original)}>
          Edit via API form
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

function normalizeTeamMember(row: TeamMember) {
  return {
    ...row,
    name: row.name.trim(),
    email: row.email.trim().toLowerCase(),
    notes: row.notes.trim(),
  }
}

export function PatternEdit2() {
  const { add } = useToast()
  const [data, setData] = useState<TeamMember[]>(initialData)
  const [pagination, setPagination] = useState<PaginationState>({
    pageIndex: 0,
    pageSize: 5,
  })
  const [sorting, setSorting] = useState<SortingState>([{ id: "name", desc: false }])
  const [columnVisibility, setColumnVisibility] = useState<VisibilityState>({
    notes: false,
  })
  const [failNextSave, setFailNextSave] = useState(false)

  const handleResetAll = useCallback(() => {
    setData(initialData)
    setFailNextSave(false)
    add({
      title: "Server demo reset",
      description:
        "The optimistic cache and simulated API state are back to the original snapshot.",
      type: "success",
    })
  }, [add])

  const simulateServerMutation = useCallback(async () => {
    await wait(900)

    if (failNextSave) {
      setFailNextSave(false)
      throw new Error("Simulated API failure. Rollback applied. Retry the change.")
    }
  }, [failNextSave])

  const columns = useMemo<ColumnDef<TeamMember>[]>(
    () => [
      {
        accessorKey: "name",
        id: "name",
        header: ({ column }) => <DataGridColumnHeader title="Name" column={column} />,
        cell: ({ cell }) => <DataGridEditableCell cell={cell} />,
        size: 180,
        meta: {
          skeleton: cellSkeletons.name,
          editor: {
            kind: "text",
            label: "Name",
            placeholder: "Avery Miles",
            required: true,
          },
        },
      },
      {
        accessorKey: "email",
        id: "email",
        header: ({ column }) => <DataGridColumnHeader title="Email" column={column} />,
        cell: ({ cell }) => <DataGridEditableCell cell={cell} />,
        size: 220,
        meta: {
          skeleton: cellSkeletons.email,
          editor: {
            kind: "email",
            label: "Email",
            placeholder: "name@company.com",
            required: true,
            validate: validateEmail,
          },
        },
      },
      {
        accessorKey: "role",
        id: "role",
        header: ({ column }) => <DataGridColumnHeader title="Role" column={column} />,
        cell: ({ cell }) => <DataGridEditableCell cell={cell} />,
        size: 180,
        meta: {
          skeleton: cellSkeletons.role,
          editor: {
            kind: "select",
            label: "Role",
            options: roleOptions,
            required: true,
          },
        },
      },
      {
        accessorKey: "workMode",
        id: "workMode",
        header: ({ column }) => <DataGridColumnHeader title="Work Mode" column={column} />,
        cell: ({ cell }) => <DataGridEditableCell cell={cell} />,
        size: 260,
        enableSorting: false,
        meta: {
          skeleton: cellSkeletons.workMode,
          cellClassName: "justify-center px-4",
          editor: {
            kind: "radio",
            label: "Work Mode",
            options: workModeOptions,
            required: true,
          },
        },
      },
      {
        accessorKey: "salary",
        id: "salary",
        header: ({ column }) => <DataGridColumnHeader title="Salary" column={column} />,
        cell: ({ cell }) => <DataGridEditableCell cell={cell} />,
        size: 220,
        meta: {
          skeleton: cellSkeletons.salary,
          cellClassName: "justify-center px-0",
          editor: {
            kind: "number",
            label: "Salary",
            min: 60000,
            max: 250000,
            step: 1000,
            required: true,
          },
        },
      },
      {
        accessorKey: "mentor",
        id: "mentor",
        header: ({ column }) => <DataGridColumnHeader title="Mentor" column={column} />,
        cell: ({ cell }) => <DataGridEditableCell cell={cell} />,
        size: 110,
        enableSorting: false,
        meta: {
          skeleton: cellSkeletons.toggle,
          cellClassName: "justify-center px-4",
          editor: {
            kind: "checkbox",
            label: "Mentor",
            description: "Mark whether this teammate is available for contributor pairing.",
          },
        },
      },
      {
        accessorKey: "active",
        id: "active",
        header: ({ column }) => <DataGridColumnHeader title="Active" column={column} />,
        cell: ({ cell }) => <DataGridEditableCell cell={cell} />,
        size: 110,
        meta: {
          skeleton: cellSkeletons.toggle,
          cellClassName: "justify-center px-4",
          editor: {
            kind: "switch",
            label: "Active",
            description: "Controls whether the teammate is currently active in the rotation.",
          },
        },
      },
      {
        accessorKey: "rating",
        id: "rating",
        header: ({ column }) => <DataGridColumnHeader title="Quality" column={column} />,
        cell: ({ cell }) => <DataGridEditableCell cell={cell} />,
        size: 150,
        meta: {
          skeleton: cellSkeletons.rating,
          cellClassName: "justify-center px-4",
          editor: {
            kind: "rating",
            label: "Quality score",
            description: "A quick internal confidence score for demo readiness.",
          },
        },
      },
      {
        accessorKey: "notes",
        id: "notes",
        header: ({ column }) => <DataGridColumnHeader title="Notes" column={column} />,
        cell: ({ cell }) => <DataGridEditableCell cell={cell} />,
        size: 260,
        enableSorting: false,
        meta: {
          skeleton: cellSkeletons.notes,
          editor: {
            kind: "textarea",
            label: "Notes",
            description:
              "This field is hidden from the table but generated automatically inside the edit dialog.",
            placeholder: "Document extra context for the row here.",
            dialogOnly: true,
          },
        },
      },
      {
        id: "actions",
        header: "",
        cell: ({ row, table }) => <ActionsCell row={row} table={table} />,
        size: 60,
        enableSorting: false,
        enableHiding: false,
        enableResizing: false,
        meta: {
          skeleton: cellSkeletons.actions,
        },
      },
    ],
    []
  )

  const editorColumns = useMemo(
    () =>
      columns.reduce<EditableDataGridColumn<TeamMember>[]>((accumulator, column) => {
        if (column.id && column.meta?.editor) {
          accumulator.push({
            id: String(column.id),
            editor: column.meta.editor as DataGridColumnEditor<TeamMember, unknown>,
          })
        }

        return accumulator
      }, []),
    [columns]
  )

  const editing = useEditableDataGrid<TeamMember>({
    data,
    setData,
    getRowId: (row) => row.id,
    editorColumns,
    onSaveCell: async ({ nextRow }) => {
      await simulateServerMutation()
      return normalizeTeamMember(nextRow)
    },
    onSaveRow: async ({ nextRow }) => {
      await simulateServerMutation()
      const normalizedRow = normalizeTeamMember(nextRow)
      add({
        title: "Server update completed",
        description: `${normalizedRow.name} was persisted through the mocked API.`,
        type: "success",
      })
      return normalizedRow
    },
    onError: (_error, context) => {
      add({
        title: "Update failed",
        description: "The optimistic update was rolled back. Retry the change when you are ready.",
        type: "error",
      })
    },
  })
  const isGridPending = editing.isGridPending()

  const table = useReactTable({
    data,
    columns,
    pageCount: Math.ceil(data.length / pagination.pageSize),
    getRowId: (row) => row.id,
    state: {
      pagination,
      sorting,
      columnVisibility,
    },
    meta: {
      editing,
    },
    columnResizeMode: "onChange",
    onPaginationChange: setPagination,
    onSortingChange: setSorting,
    onColumnVisibilityChange: setColumnVisibility,
    getCoreRowModel: getCoreRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    getSortedRowModel: getSortedRowModel(),
  })

  return (
    <DataGrid
      table={table}
      recordCount={data.length}
      loadingMode="skeleton"
      tableLayout={{
        columnsResizable: false,
        headerSticky: true,
        cellBorder: true,
      }}
      tableClassNames={{
        headerSticky: "sticky top-0 z-10 bg-background/90 backdrop-blur-xs",
      }}
    >
      <Card className="w-full gap-0 p-0">
        <CardHeader className="flex items-center justify-between gap-3 px-4 py-3">
          <div className="flex items-center gap-2">
            <span className="text-foreground text-sm font-medium">Async Editing Sandbox</span>
            <Badge variant="info-outline">Optimistic API</Badge>
            {isGridPending ? (
              <Badge variant="outline">
                <Spinner className="size-3" />
                Saving row
              </Badge>
            ) : null}
            {failNextSave ? <Badge variant="destructive">Fail next save</Badge> : null}
          </div>
          <div className="flex items-center gap-2">
            <Button
              variant={failNextSave ? "destructive" : "outline"}
              size="xs"
              onClick={() => setFailNextSave((currentValue) => !currentValue)}
              disabled={isGridPending}
            >
              <TriangleAlertIcon className="size-3" />
              {failNextSave ? "Failure armed" : "Fail next save"}
            </Button>
            <Button variant="outline" size="xs" onClick={handleResetAll} disabled={isGridPending}>
              <RotateCcwIcon className="size-3" />
              Reset demo
            </Button>
          </div>
        </CardHeader>
        <CardContent className="border-y p-0">
          <DataGridScrollArea className="h-[460px]">
            <DataGridTable />
          </DataGridScrollArea>
        </CardContent>
        <CardFooter className="border-none bg-transparent! px-4 py-3">
          <DataGridPagination />
        </CardFooter>
      </Card>

      <DataGridEditDialog
        table={table}
        title="Edit teammate over API"
        description="The grid commits optimistically, then the mocked API either confirms the update or rolls it back."
      />
    </DataGrid>
  )
}

const DataGridAsyncEditingPreview = PatternEdit2

function DataGridAsyncEditingToastPreview() {
  return (
    <ToastProvider>
      <DataGridAsyncEditingPreview />
    </ToastProvider>
  )
}

